trigger ContactTrigger on Contact (after insert, after update) {
    for (Contact con : Trigger.new) {
        Account acc = [SELECT Id, Total_Contacts__c, OwnerId FROM Account WHERE Id = con.AccountId];

        if (Trigger.isInsert) {
            acc.Total_Contacts__c++;
        } else if (Trigger.isUpdate && con.LastName != Trigger.oldMap.get(con.Id).LastName) {
            // Check if last name changed
            acc.Total_Contacts__c += (Trigger.new.size() - Trigger.oldMap.size());
        }

        update acc;

        if (con.LastName == 'Smith') {
            Task t = new Task();
            t.Subject = 'Follow up with Smith Contact';
            t.WhatId = acc.Id;
            t.WhoId = acc.OwnerId;
            insert t;
        }
}
